    it('should declare all anatomy parts', () => {
      const parts = ["root","label","track","range","thumbMin","thumbMax","outputMin","outputMax"];
      expect(parts.length).toBe(8);
      expect(parts).toContain('root');
      expect(parts).toContain('label');
      expect(parts).toContain('track');
      expect(parts).toContain('range');
      expect(parts).toContain('thumbMin');
      expect(parts).toContain('thumbMax');
      expect(parts).toContain('outputMin');
      expect(parts).toContain('outputMax');
    });

    it('should assign semantic roles to anatomy parts', () => {
      expect('container').toBeTruthy(); // root: container
      expect('text').toBeTruthy(); // label: text
      expect('container').toBeTruthy(); // track: container
      expect('container').toBeTruthy(); // range: container
      expect('action').toBeTruthy(); // thumbMin: action
      expect('action').toBeTruthy(); // thumbMax: action
      expect('text').toBeTruthy(); // outputMin: text
      expect('text').toBeTruthy(); // outputMax: text
    });

